// Draw sound buttons using a table-grid approach (OpenDyslexic font).
// Each letter gets an equal-width table cell — layout is font-agnostic.
// Dots/lines drawn as floating shapes below the table.
// Split-digraph arcs are collected in SB_ARC_DATA for Python injection.
// cx = centre x, wy = top y of the word display, slideNum = 1-based slide index.
function drawSoundButtons(slide, word, cx, wy, fontSize, slideNum) {
  const groups = PHONEMES[word];
  if (!groups) {
    console.warn(`PHONEME WARNING: No entry for "${word}" — sound buttons skipped.`);
    return;
  }
  // Validate: total letters in phoneme groups must equal word length
  const coveredLetters = groups.reduce((sum, g) => sum + g.l.length, 0);
  if (coveredLetters !== word.replace(/[^a-zA-Z]/g, '').length) {
    console.warn(`PHONEME WARNING: "${word}" has ${word.length} letters but phoneme data covers ${coveredLetters} — check for missing vowels or split digraph sid entries. Sound buttons skipped.`);
    return;
  }

  // Scaled constants (calibrated at 28pt reference)
  const CELL_W = fontSize / 28 * 0.40;               // cell width per letter
  const ROW_H  = fontSize * 1.4 / 72;                // table row height
  const DOT    = Math.max(0.040, fontSize * 0.084 / 28); // dot/oval diameter
  const LINE_H = Math.max(0.018, fontSize * 0.046 / 28); // digraph bar height
  const PAD    = CELL_W * 0.07;                       // inset at each end of digraph bar
  const GAP    = 0.04;                                // gap between table bottom and symbols
  const ARC_H  = 0.236;                               // split-digraph arc depth (0.6 cm)

  const nCells = groups.reduce((sum, g) => sum + g.l.length, 0);
  const totalW = nCells * CELL_W;
  const tableX = cx - totalW / 2;
  const symY   = wy + ROW_H + GAP;
  const lineY  = symY + (DOT - LINE_H) / 2;

  // Table: one cell per letter, all borders hidden, OpenDyslexic font
  const NB = { type: 'none' };
  const row = groups.flatMap(g =>
    [...g.l].map(ch => ({
      text: ch,
      options: {
        align: 'center', valign: 'middle',
        fontSize, fontFace: 'OpenDyslexic', color: '000000', bold: false,
        margin: 0, border: [NB, NB, NB, NB], fill: { type: 'none' },
      }
    }))
  );
  slide.addTable([row], {
    x: tableX, y: wy, w: totalW, h: ROW_H,
    colW: Array(nCells).fill(CELL_W),
    rowH: [ROW_H],
  });

  // Per-group geometry
  let col = 0;
  const gd = groups.map(g => {
    const n  = g.l.length;
    const gx = tableX + col * CELL_W;
    const gw = n * CELL_W;
    col += n;
    return { ...g, gx, gw, gc: gx + gw / 2 };
  });

  // Digraph bars (padded so adjacent digraphs stay visually distinct)
  gd.filter(g => g.t === 'line').forEach(g => {
    slide.addShape(pres.shapes.RECTANGLE, {
      x: g.gx + PAD, y: lineY,
      w: g.gw - 2 * PAD, h: LINE_H,
      fill: { color: C.BLACK }, line: { color: C.BLACK, width: 0 }
    });
  });

  // Dots (single phonemes only — split-digraph letters get arc end-caps, not dots)
  gd.filter(g => g.t === 'dot' && g.sid === undefined).forEach(g => {
    slide.addShape(pres.shapes.OVAL, {
      x: g.gc - DOT / 2, y: symY,
      w: DOT, h: DOT,
      fill: { color: C.BLACK }, line: { color: C.BLACK, width: 0 }
    });
  });

  // Split-digraph arcs — collected for Python bezier injection
  const splits = {};
  gd.forEach(g => { if (g.sid !== undefined) (splits[g.sid] = splits[g.sid] || []).push(g); });
  Object.values(splits).forEach(pair => {
    if (pair.length < 2) return;
    pair.sort((a, b) => a.gx - b.gx);
    const x1 = pair[0].gc, x2 = pair[pair.length - 1].gc;
    SB_ARC_DATA.push({ slide: slideNum, x: x1, y: symY, w: x2 - x1, h: ARC_H,
                       lineEmu: Math.round(Math.max(1.0, fontSize * 0.046 / 28 * 72) * 12700) });
  });
}

// ── Helper: fit font size to box width ───────────────────
// Returns the largest font size (≤ maxPt, ≥ minPt) where `text`
// fits on one line in a box of `boxW` inches using Calibri.
// Empirical Calibri character width: ~0.54em (0.54 * pt / 72 inches avg).
// Uses margin:0 — callers must also set margin:0 on the text box.
function fitFontSize(text, boxW, maxPt = 36, minPt = 14) {
  const AVG_CHAR_W = 0.54;   // em units (fraction of point size)
  const nChars = text.replace(/\s/g, '').length || text.length;
  // Required pt so text fills exactly boxW:
  const required = (boxW * 72) / (nChars * AVG_CHAR_W);
  return Math.round(Math.min(maxPt, Math.max(minPt, required)));
}

// ── Helper: draw the standard frame ──────────────────────
// activityType: "Whole Group" | "Independent"
// activityLabel: "Starter" etc.
// question: the blue bold question line
// slideNum: `${LESSON.code}.1` etc.
function addFrame(slide, activityType, activityLabel, question, slideNum) {
  // White header background (implicit — slide default is white)

  // Left-hand type indicator (replaces bee image since we can't use Spelling Shed's artwork)
  const indCol = activityType === "Independent" ? "F4C430" : "66BB6A";
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0.1, y: 0.1, w: 1.35, h: 0.92,
    fill: { color: indCol }, line: { color: indCol, width: 0 }
  });
  slide.addText(activityType, {
    x: 0.1, y: 0.1, w: 1.35, h: 0.92,
    fontSize: 12, fontFace: "Calibri", bold: true, color: C.WHITE,
    align: "center", valign: "middle", margin: 0
  });

  // Activity label — centred, regular weight, black
  slide.addText(activityLabel, {
    x: 1.55, y: 0.06, w: 7.5, h: 0.44,
    fontSize: 19, fontFace: "Calibri", color: C.BLACK,
    align: "center", valign: "middle"
  });

  // Question — centred, bold, blue
  slide.addText(question, {
    x: 1.55, y: 0.5, w: 7.5, h: 0.6,
    fontSize: 22, fontFace: "Calibri", bold: true, color: C.BLUE,
    align: "center", valign: "middle"
  });

  // Slide number — small grey, bottom-right of header
  slide.addText(slideNum, {
    x: 8.85, y: 0.78, w: 1.05, h: 0.28,
    fontSize: 14, fontFace: "Calibri", color: C.GREY,
    align: "right", valign: "middle"
  });

  // Cyan separator stripe
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: HDR_H, w: SW, h: CYAN_H,
    fill: { color: C.CYAN }, line: { color: C.CYAN, width: 0 }
  });

  // Green bottom bar
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: BAR_Y, w: SW, h: SH - BAR_Y,
    fill: { color: C.GREEN_B }, line: { color: C.GREEN_B, width: 0 }
  });
}

