// ── Slide 3: Starter (answers) ────────────────────────────
// Shape ID sequence (addFrame=2-8, then per pair: base/ans/rule = 3 shapes):
// Pair 0 (play):  base=9  ans=10  rule=11  → click 1: 10,11
// Pair 1 (carry): base=12 ans=13  rule=14  → click 2: 13,14
// Pair 2 (enjoy): base=15 ans=16  rule=17  → click 3: 16,17
// Pair 3 (study): base=18 ans=19  rule=20  → click 4: 19,20
// Pair 4 (say):   base=21 ans=22  rule=23  → click 5: 22,23
// Pair 5 (hurry): base=24 ans=25  rule=26  → click 6: 25,26
// Rule border=27, Rule text=28
{
  const s = pres.addSlide();
  addFrame(s, "Whole Group", "Starter",
    "How did the base verb change?", `${LESSON.code}.2`);

  const answers = LESSON.starter.words.map((w, i) => ({ base: w, result: LESSON.starter.answers[i], vowel: false }));

  const cellW = 9.0 / 3;
  const sx = 0.5, sy = CONT_Y + 0.15;
  const BASE_H = 0.52, ANS_H = 0.50, RULE_H = 0.28;
  const PAIR_H = BASE_H + ANS_H + RULE_H; // 1.30"
  const rowGap = 0.20;

  // addFrame = 7 shapes (IDs 2-8); each pair adds 3 shapes
  const _starterFontSize = Math.min(
    ...answers.map(a => Math.min(fitFontSize(a.base + "  →", cellW, 28, 14),
                                 fitFontSize(a.result, cellW, 28, 14))));
  answers.forEach((item, i) => {
    const col = i % 3, row = Math.floor(i / 3);
    const x  = sx + col * cellW;
    const y  = sy + row * (PAIR_H + rowGap);

    // (1) BASE word + arrow — always visible
    s.addText(item.base + "  →", {
      x, y, w: cellW, h: BASE_H,
      fontSize: _starterFontSize, fontFace: "Calibri", color: C.BLACK,
      align: "center", valign: "middle"
    });

    // (2) ANSWER — animated (click i+1)
    s.addText(item.result, {
      x, y: y + BASE_H, w: cellW, h: ANS_H,
      fontSize: _starterFontSize, fontFace: "Calibri", bold: true, color: C.PINK,
      align: "center", valign: "middle"
    });

    // (3) RULE shape — animated with answer (must keep same shape count for animation IDs)
    // Shows a short per-pair note; empty string for rules where no per-pair note is needed
    s.addText(LESSON.starter.perPairNote || "", {
      x, y: y + BASE_H + ANS_H, w: cellW, h: RULE_H,
      fontSize: 11, fontFace: "Calibri", italic: true, color: C.GREY,
      align: "center", valign: "middle"
    });
  });

  // Rule box at bottom — always visible (IDs 27, 28)
  const ruleY = sy + 2 * (PAIR_H + rowGap) + 0.14;
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: ruleY, w: 9.0, h: 0.45,
    fill: { color: "FFF9C4" }, line: { color: C.YELLOW, width: 1.5 }
  });
  s.addText(LESSON.starter.ruleBox, {
    x: 0.5, y: ruleY, w: 9.0, h: 0.45,
    fontSize: 16, fontFace: "Calibri", bold: true, color: C.BLACK,
    align: "center", valign: "middle", margin: 0
  });
}

