// ── Slide 21: Morphology Matrix (answers) ────────────────
{
  const s = pres.addSlide();
  addFrame(s, "Whole Group", "Morphology Matrix",
    "How many new words can you create by adding suffix(es)?", `${LESSON.code}.20`);

  s.addText("Base Word", {
    x: 0.4, y: CONT_Y + 0.15, w: 4.2, h: 0.38,
    fontSize: 20, fontFace: "Calibri", bold: true, color: C.GREEN_S,
    align: "center"
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.4, y: CONT_Y + 0.55, w: 4.2, h: 3.45,
    fill: { color: C.WHITE }, line: { color: C.GREEN_S, width: 2.5 }
  });
  s.addText(LESSON.morphMatrix.baseWord, {
    x: 0.4, y: CONT_Y + 0.85, w: 4.2, h: 1.5,
    fontSize: 64, fontFace: "Calibri", color: C.BLACK,
    align: "center", valign: "middle"
  });
  s.addText(LESSON.morphMatrix.def, {
    x: 0.6, y: CONT_Y + 2.55, w: 3.8, h: 0.6,
    fontSize: 13, fontFace: "Calibri", italic: true, color: C.GREY,
    align: "center", valign: "middle"
  });

  s.addText("Suffix", {
    x: 5.0, y: CONT_Y + 0.15, w: 4.6, h: 0.38,
    fontSize: 20, fontFace: "Calibri", bold: true, color: C.PURPLE,
    align: "center"
  });

  const suffixAnswers = LESSON.morphMatrix.suffixes.map((sf, i) => ({ sf, ans: LESSON.morphMatrix.answers[i] }));
  const gcw = 2.3, grh = 0.84;
  suffixAnswers.forEach((item, i) => {
    const col = i % 2, row = Math.floor(i / 2);
    const x = 5.0 + col * gcw;
    const y = CONT_Y + 0.55 + row * grh;
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: gcw, h: grh,
      fill: { color: C.WHITE }, line: { color: C.PURPLE, width: 2 }
    });
    s.addText([
      { text: item.sf + "\n",  options: { fontSize: 14, color: C.GREY, breakLine: true } },
      { text: item.ans,        options: { fontSize: 22, color: C.PINK, bold: true } },
    ], { x, y, w: gcw, h: grh, fontFace: "Calibri", align: "center", valign: "middle", margin: 0 });
  });
}

